var be = require('./');
var async = require('async');
var suite = new (require('benchmark').Benchmark.Suite);

var task = function(next){
    process.nextTick(next.bind(null, null));
};

var n = 10;
var tasksa = [], taskso = {};
while (n--) {
    tasksa.push(task);
    taskso[n] = task;
}

suite
.add('async.series#array', {
        defer: true,
        fn: function(deferred) {
            async.series(tasksa, function(err, acc){
                deferred.resolve();
            });
        }
})
.add('be.series#array', {
        defer: true,
        fn: function(deferred) {
            be.series(tasksa, function(err, acc){
                deferred.resolve();
            });
        }
})
.add('async.series#object', {
        defer: true,
        fn: function(deferred) {
            async.series(taskso, function(err, acc){
                deferred.resolve();
            });
        }
})
.add('be.series#object', {
        defer: true,
        fn: function(deferred) {
            be.series(taskso, function(err, acc){
                deferred.resolve();
            });
        }
})
.add('async.waterfall#array', {
    defer: true,
    fn: function(deferred){
        async.waterfall(tasksa, function() {
            deferred.resolve();
        });
    }
})
.add('be.waterfall#array', {
    defer: true,
    fn: function(deferred){
        be.waterfall(tasksa, function() {
            deferred.resolve();
        });
    }
})
.add('async.parallel#array', {
    defer: true,
    fn: function(deferred){
        async.parallel(tasksa, function() {
            deferred.resolve();
        });
    }
})
.add('be.parallel#array', {
    defer: true,
    fn: function(deferred){
        be.parallel(tasksa, function() {
            deferred.resolve();
        });
    }
})
.add('async.parallel#object', {
    defer: true,
    fn: function(deferred){
        async.parallel(taskso, function() {
            deferred.resolve();
        });
    }
})
.add('be.parallel#object', {
    defer: true,
    fn: function(deferred){
        be.parallel(taskso, function() {
            deferred.resolve();
        });
    }
})
.add('async.each', {
    defer: true,
    fn: function(deferred){
        async.each([1,2,3,4,5], function(n, next){
            next();
        }, function() {
            deferred.resolve();
        });
    }
})
.add('be.each', {
    defer: true,
    fn: function(deferred){
        be.each([1,2,3,4,5], function(n, next){
            next();
        }, function() {
            deferred.resolve();
        });
    }
})
.add('async.eachSeries', {
    defer: true,
    fn: function(deferred){
        async.eachSeries([1,2,3,4,5], function(n, next){
            next();
        }, function() {
            deferred.resolve();
        });
    }
})
.add('be.eachSeries', {
    defer: true,
    fn: function(deferred){
        be.eachSeries([1,2,3,4,5], function(n, next){
            next();
        }, function() {
            deferred.resolve();
        });
    }
})
.add('async.map', {
    defer: true,
    fn: function(deferred){
        async.map([1,2,3,4,5], function(n, next){
            next(null, n);
        }, function() {
            deferred.resolve();
        });
    }
})
.add('be.map', {
    defer: true,
    fn: function(deferred){
        be.map([1,2,3,4,5], function(n, next){
            next(null, n);
        }, function() {
            deferred.resolve();
        });
    }
})
.on('cycle', function(event) {
  console.log(String(event.target));
})
.run();


